from collections import defaultdict

def solve(grid):
    H = len(grid)
    W = len(grid[0])
    out = copy.deepcopy(grid)
    bg = grid[0][0]

    blues = []
    magentas = set()
    for r in range(H):
        for c in range(W):
            if grid[r][c] == 1:
                blues.append((r, c))
            elif grid[r][c] == 6:
                magentas.add((r, c))

    cross_magentas = []

    # Group blues by diagonal (r-c) and anti-diagonal (r+c)
    diag_groups = defaultdict(list)
    anti_groups = defaultdict(list)
    for r, c in blues:
        diag_groups[r - c].append((r, c))
        anti_groups[r + c].append((r, c))

    # Process diagonal groups (r-c = const, movement along +1,+1)
    for key, group in diag_groups.items():
        if len(group) >= 2:
            group.sort()
            r1, c1 = group[0]
            r2, c2 = group[-1]
            for i in range(r2 - r1 + 1):
                r, c = r1 + i, c1 + i
                if (r, c) in magentas:
                    cross_magentas.append(((r, c), 'anti'))
                else:
                    out[r][c] = 1

    # Process anti-diagonal groups (r+c = const, movement along +1,-1)
    for key, group in anti_groups.items():
        if len(group) >= 2:
            group.sort()
            r1, c1 = group[0]
            r2, c2 = group[-1]
            for i in range(r2 - r1 + 1):
                r, c = r1 + i, c1 - i
                if (r, c) in magentas:
                    cross_magentas.append(((r, c), 'diag'))
                else:
                    out[r][c] = 1

    # Draw cross-diagonals
    for (mr, mc), perp_type in cross_magentas:
        if perp_type == 'anti':  # perpendicular to main diag, so anti-diag direction
            for dr, dc in [(-1, 1), (1, -1)]:
                r, c = mr + dr, mc + dc
                while 0 <= r < H and 0 <= c < W:
                    out[r][c] = 6
                    r += dr
                    c += dc
        else:  # perpendicular to anti-diag, so main diag direction
            for dr, dc in [(-1, -1), (1, 1)]:
                r, c = mr + dr, mc + dc
                while 0 <= r < H and 0 <= c < W:
                    out[r][c] = 6
                    r += dr
                    c += dc

    return out

# Test on all training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    match = result == s['output']
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        # Find differences
        for r in range(len(result)):
            for c in range(len(result[0])):
                if result[r][c] != s['output'][r][c]:
                    print(f"  Diff at ({r},{c}): got {result[r][c]}, expected {s['output'][r][c]}")

